+
+        // External ids: 7, 20, 33, 46, … — non-dense, strictly
+        // monotonic but unequal to `0..n`. Largest is 13·49 + 7 = 644
+        // so still fits comfortably in u32.
+        let external_ids: Vec<usize> = (0..n).map(|i| i * 13 + 7).collect();
